#include <bits/stdc++.h>
#define int long long
using namespace std;
const int N = 500005;
int n, k;
int head[N * 2];
int nxt[N * 2];
int to[N * 2];
int edge;
int fa[N][20];
int dep[N];
int w1[N], w2[N];
int ans;
void addEdge(int x, int y) {
    to[edge] = y;
    nxt[edge] = head[x];
    head[x] = edge++;
    to[edge] = x;
    nxt[edge] = head[y];
    head[y] = edge++;
    return ;
}
void init () {
    for (int j = 1; (1 << j) <= n; ++j) {
        for (int i = 1; i <= n; ++i) {
            if (fa[i][j - 1] != -1) {
                fa[i][j] = fa[fa[i][j - 1]][j - 1];
            }
        }
    }
    return;
}
void dfs (int u, int FA, int step) {
	fa[u][0] = FA;
	dep[u] = step;
	for (int e = head[u]; (~e); e = nxt[e]) {
		int& v = to[e];
		if (v != FA) {
			dfs (v, u, step + 1);
		}
	}
	return ;
}
int lca (int u, int v) {
	if (dep[u] < dep[v]) {
		swap (u, v);
	}
	int k = 0;
	for (; (1 << k) <= n; k++) {
		;
	}
	k--;
	for (int j = k; j >= 0; j--) {
		if (dep[u] - (1 << j) >= dep[v]) {
			u = fa[u][j];
		}
	}
	if (u == v) {
		return u;
	}
	for (int j = k; j >= 0; j--) {
		if (fa[v][j] != fa[u][j] && fa[u][j] != -1) {
			u = fa[u][j];
			v = fa[v][j];
		} 
	}
	return fa[u][0];
}
void check (int x, int y) {
	int z = lca (x, y);
	w1[x]++;
	w1[y]++;
	w1[z]--;
	if (fa[z][0] != -1) {
		w1[fa[z][0]]--;
	}
	return ;
}
void dfs2 (int x, int FA) {
    w2[x] = w1[x];
    for (int e = head[x]; ~e; e = nxt[e]) {
        int& v = to[e];
        if (v != FA) {
            dfs2 (v, x);
            w2[x] += w2[v];
        }
    }
    ans = max (ans, w2[x]);
    return;
}
signed main () {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	memset (head, -1, sizeof (head));
	memset (fa, -1, sizeof (fa));
	cin >> n >> k;
	for (int i = 1; i < n; i++) {
		int u, v;
		cin >> u >> v;
		addEdge (u, v);
	}
	dfs (1, 0, 1);
	init ();
	while (k--) {
		int x, y;
		cin >> x >> y;
		check (x, y);
	}
	dfs2 (1, 0);
	cout << ans;
	return 0;
}
